import { SectionHeader as BaseSectionHeader } from '@/vendor/untitled-ui/application/section-headers/section-headers';
import { cx } from '@/utils/cx';
import { InputSearchField } from '@/components/atoms/Input';
import { WithDataId } from '@/types/withDataId';

export const SectionHeading = {
  Root,
  Group,
  Header,
  Actions,
  Search,
};

function Root(
  props: React.ComponentPropsWithRef<typeof BaseSectionHeader.Root> &
    WithDataId,
) {
  return <BaseSectionHeader.Root {...props} />;
}

function Group(
  props: React.ComponentPropsWithRef<typeof BaseSectionHeader.Group>,
) {
  return <BaseSectionHeader.Group {...props} />;
}

type HeaderProps = {
  title: React.ReactNode;
  subtitle?: React.ReactNode;
  className?: string;
};

function Header({ title, subtitle, className }: HeaderProps) {
  return (
    <div className={cx('flex flex-col gap-0.5 flex-1', className)}>
      <BaseSectionHeader.Heading>{title}</BaseSectionHeader.Heading>
      {subtitle && (
        <BaseSectionHeader.Subheading>{subtitle}</BaseSectionHeader.Subheading>
      )}
    </div>
  );
}

function Actions(
  props: React.ComponentPropsWithRef<typeof BaseSectionHeader.Actions> &
    WithDataId,
) {
  return (
    <BaseSectionHeader.Actions
      {...props}
      data-id={props['data-id']}
    />
  );
}
function Search(
  props: React.ComponentPropsWithoutRef<typeof InputSearchField>,
) {
  return (
    <div className="w-full md:w-80">
      <InputSearchField {...props} />
    </div>
  );
}
